export function script(input) {
  const defaultWords = ['robots.txt', 'sitemap.xml', 'api', 'api/health', 'health', 'status', 'swagger.json', 'openapi.json', 'graphql', 'admin', 'login', 'debug', 'metrics'];
  const intensityLimits = { safe: 25, normal: 60, thorough: 120 };
  const requestedIntensity = String(input.scanIntensity || 'safe').trim().toLowerCase();
  const intensity = Object.prototype.hasOwnProperty.call(intensityLimits, requestedIntensity) ? requestedIntensity : 'safe';
  const limit = intensityLimits[intensity];
  function asWords(value) {
    if (Array.isArray(value)) return value;
    if (typeof value === 'string' && value.trim()) return value.split(/[\n,]+/);
    return [];
  }
  function cleanWord(value) {
    return String(value || '').trim().replace(/^\/+/, '').replace(/[?#].*$/, '');
  }
  const requestedWords = asWords(input.wordlist);
  const sourceWords = requestedWords.length > 0 ? requestedWords : defaultWords;
  const selectedWords = [];
  const seen = new Set();
  for (const word of sourceWords) {
    const cleaned = cleanWord(word);
    if (!cleaned || cleaned.includes('..') || /^https?:\/\//i.test(cleaned) || cleaned.includes('FUZZ')) continue;
    if (seen.has(cleaned)) continue;
    seen.add(cleaned);
    selectedWords.push(cleaned);
    if (selectedWords.length >= limit) break;
  }
  if (selectedWords.length === 0) selectedWords.push('robots.txt');
  function normalizeTarget(value) {
    const raw = String(value || '').trim();
    const withScheme = /^[a-z][a-z0-9+.-]*:\/\//i.test(raw) ? raw : `https://${raw}`;
    try {
      const parsed = new URL(withScheme);
      parsed.hash = '';
      if (parsed.pathname.includes('FUZZ')) return parsed.toString();
      if (!parsed.pathname || parsed.pathname === '/') {
        parsed.pathname = '/FUZZ';
      } else {
        parsed.pathname = parsed.pathname.replace(/\/?$/, '/FUZZ');
      }
      return parsed.toString();
    } catch {
      return raw.includes('FUZZ') ? raw : `${raw.replace(/\/+$/, '')}/FUZZ`;
    }
  }
  const ffufTarget = normalizeTarget(input.targetUrl);
  return {
    ffufTarget,
    wordlistText: selectedWords.join(String.fromCharCode(10)),
    scanProfile: {
      intensity,
      wordCount: selectedWords.length,
      requestedWordCount: requestedWords.length,
      wordLimit: limit,
      truncatedByIntensity: Math.max(0, sourceWords.length - selectedWords.length),
      targetInput: String(input.targetUrl || '').trim(),
      ffufTarget,
    },
  };
}

export function script(input) {
  const list = (value) => Array.isArray(value) ? value : [];
  const scanProfile = input.scanProfile && typeof input.scanProfile === 'object' ? input.scanProfile : {};
  const severityRank = { high: 4, medium: 3, low: 2, info: 1 };
  function classify(entry) {
    const status = Number(entry?.status || 0);
    if (status >= 500) return { severity: 'high', reason: 'Server error from fuzzed path' };
    if (status === 401 || status === 403) return { severity: 'medium', reason: 'Auth-protected path discovered' };
    if (status >= 300 && status < 400) return { severity: 'low', reason: 'Redirecting path discovered' };
    if (status >= 200 && status < 300) return { severity: 'info', reason: 'Responsive path discovered' };
    return null;
  }
  const priorityFindings = list(input.discoveries).map((entry) => {
    const classification = classify(entry);
    if (!classification) return null;
    return {
      source: 'ffuf',
      url: String(entry?.url || ''),
      status: Number(entry?.status || 0),
      length: Number(entry?.length || 0),
      words: Number(entry?.words || 0),
      lines: typeof entry?.lines === 'number' ? entry.lines : null,
      redirectLocation: entry?.redirectlocation || null,
      severity: classification.severity,
      reason: classification.reason,
    };
  }).filter(Boolean).filter((item) => item.url.length > 0).sort((a, b) => (severityRank[b.severity] || 0) - (severityRank[a.severity] || 0) || b.status - a.status || a.url.localeCompare(b.url));
  const countsBySeverity = priorityFindings.reduce((acc, item) => { acc[item.severity] = (acc[item.severity] || 0) + 1; return acc; }, {});
  const serverErrors = priorityFindings.filter((item) => item.status >= 500).length;
  const authProtected = priorityFindings.filter((item) => item.status === 401 || item.status === 403).length;
  const redirects = priorityFindings.filter((item) => item.status >= 300 && item.status < 400).length;
  const responsive = priorityFindings.filter((item) => item.status >= 200 && item.status < 300).length;
  return {
    report: {
      summary: {
        targetUrl: input.targetUrl || scanProfile.ffufTarget || null,
        discoveries: priorityFindings.length,
        serverErrors,
        authProtected,
        redirects,
        responsive,
        highestSeverity: priorityFindings[0]?.severity || null,
        countsBySeverity,
        intensity: scanProfile.intensity || 'safe',
        wordCount: Number(scanProfile.wordCount || 0),
      },
      authorizationNotes: input.authorizationNotes || null,
      scanProfile,
      priorityFindings: priorityFindings.slice(0, 100),
      rawDiscoveries: list(input.discoveries).slice(0, 100),
      nextSteps: ['Manually validate every discovered path inside the authorized scope', 'Review 401/403 paths for access-control bypass opportunities', 'Inspect 5xx responses for reproducible low-impact error handling issues', 'Avoid destructive requests or state-changing fuzzing without explicit program permission'],
    },
  };
}
